#include <bits/stdc++.h>
using namespace std;

int findMaxConsecutiveOnes(vector<int> &nums)
{
    int n = nums.size();

    int count = 0;
    int max1 = 0;
    for (int i = 0; i < n; i++)
    {
        if (nums[i] == 1)
            count++;
        else
        {
            count = 0;
        }
        max1 = max(count, max1);
    }
    return max1;
}

